UPDATE public.questions SET
  stimulus_text = 'The first time I saw her, she was sitting in a cafe, reading a book. Her long hair cascaded down her back, framing her face, and her eyes were bright with intelligence. She was wearing a simple white dress that flowed gracefully around her, making her appear almost ethereal. She was the most beautiful woman I had ever seen. Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
