UPDATE public.questions SET
  stimulus_text = 'The author of "The Great Gatsby" is known for his elegant style and his descriptions of lavish parties.  However, many critics have pointed to the novel’s use of symbolism as a way to explore a larger theme.  The story''s setting, in the Roaring Twenties of New York, is often interpreted as representing the rise and fall of the American Dream, and the green light across the bay can be seen as a symbol of hope and the unattainable.',
